1	// Edge function: apify-webhook (US-016)
2	//
3	// Contract:
4	//   POST (headers include X-Apify-Webhook-Secret)
5	//     body: {
6	//       eventType: 'ACTOR.RUN.SUCCEEDED'|'ACTOR.RUN.FAILED'
7	//                 |'ACTOR.RUN.TIMED_OUT'|'ACTOR.RUN.ABORTED',
8	//       resource: { id, defaultDatasetId, status, actId },
9	//       social_link_id, scrape_mode, run_id,
10	//       status?, apify_finished_at?, dataset_id?,   // injected via payloadTemplate
11	//     }
12	//     → 200 { ok: true, inserted?: bool, duplicate?: bool, skipped?: 'unsupported_scrape_mode' }
13	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
14	//     → 401 { error: 'UNAUTHORIZED' }
15	//     → 405 { error: 'METHOD_NOT_ALLOWED' }
16	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'APIFY_FETCH_ERROR' }
17	//
18	// Auth: no JWT — webhook-auth via constant-time compare of the
19	//   X-Apify-Webhook-Secret header against env APIFY_WEBHOOK_SECRET or
20	//   APIFY_WEBHOOK_SECRET_PREVIOUS (dual-secret rotation window per
21	//   docs/tech-architecture.md §3g). Deploy with --no-verify-jwt.
22	//
23	// Idempotency: the RPC public.apify_webhook_persist_tiktok_profile inserts
24	//   one metric_snapshots row keyed on apify_run_id; the partial unique index
25	//   metric_snapshots_run_uniq makes the second webhook for the same run a
26	//   no-op. RPC returns {inserted, duplicate, snapshot_id?}.
27	//
28	// Scope (US-016): tiktok_profile branch only. ig_details / ig_posts return
29	//   200 { skipped: 'unsupported_scrape_mode' } so Apify doesn't retry; the
30	//   matching branches ship with US-017.
31	//
32	// Pre-refreshing-row note (US-020 handoff): the RPC currently INSERTs (never
33	//   UPDATEs), so it assumes no existing snapshot row carries this apify_run_id.
34	//   US-020 (auth-signup-creator Apify dispatch) will pre-create snapshots in
35	//   status='refreshing' before the webhook arrives — at that point this RPC
36	//   (or the denorm trigger) must be extended to UPDATE-then-denorm. See the
37	//   spec-gap note in the us_016_apify_webhook_persist_rpc migration.
38	
39	import { createClient } from "npm:@supabase/supabase-js@2";
40	import { corsHeaders } from "../_shared/cors.ts";
41	
42	const APIFY_API_BASE = "https://api.apify.com/v2";
43	
44	interface WebhookBody {
45	  eventType?: unknown;
46	  resource?: unknown;
47	  social_link_id?: unknown;
48	  scrape_mode?: unknown;
49	  run_id?: unknown;
50	  status?: unknown;
51	  apify_finished_at?: unknown;
52	  dataset_id?: unknown;
53	}
54	
55	interface ApifyResource {
56	  id: string;
57	  defaultDatasetId: string;
58	  status: string;
59	  actId: string;
60	}
61	
62	interface TikTokAuthorMeta {
63	  fans?: number;
64	  following?: number;
65	  heart?: number;
66	  video?: number;
67	  verified?: boolean;
68	}
69	
70	interface TikTokItem {
71	  authorMeta?: TikTokAuthorMeta;
72	  playCount?: number;
73	}
74	
75	type MetricStatus = "fresh" | "failed";
76	
77	type ScrapeMode = "tiktok_profile" | "ig_details" | "ig_posts";
78	
79	const SUCCEEDED_EVENT = "ACTOR.RUN.SUCCEEDED";
80	const TERMINAL_EVENT_TYPES = new Set([
81	  SUCCEEDED_EVENT,
82	  "ACTOR.RUN.FAILED",
83	  "ACTOR.RUN.TIMED_OUT",
84	  "ACTOR.RUN.ABORTED",
85	]);
86	
87	function jsonResponse(status: number, body: unknown): Response {
88	  return new Response(JSON.stringify(body), {
89	    status,
90	    headers: { ...corsHeaders, "Content-Type": "application/json" },
91	  });
92	}
93	
94	function isNonEmptyString(value: unknown): value is string {
95	  return typeof value === "string" && value.length > 0;
96	}
97	
98	// Constant-time string compare. Lengths are compared first; when lengths
99	// differ we still iterate over the longer string to keep timing flat.
100	function timingSafeEqual(a: string, b: string): boolean {
101	  const enc = new TextEncoder();
102	  const aBytes = enc.encode(a);
103	  const bBytes = enc.encode(b);
104	  const len = Math.max(aBytes.length, bBytes.length);
105	  let diff = aBytes.length ^ bBytes.length;
106	  for (let i = 0; i < len; i++) {
107	    const ac = i < aBytes.length ? aBytes[i] : 0;
108	    const bc = i < bBytes.length ? bBytes[i] : 0;
109	    diff |= ac ^ bc;
110	  }
111	  return diff === 0;
112	}
113	
114	function verifyWebhookSecret(req: Request): boolean {
115	  const provided = req.headers.get("x-apify-webhook-secret");
116	  if (!isNonEmptyString(provided)) return false;
117	  const current = Deno.env.get("APIFY_WEBHOOK_SECRET") ?? "";
118	  const previous = Deno.env.get("APIFY_WEBHOOK_SECRET_PREVIOUS") ?? "";
119	  if (!current && !previous) return false;
120	  let ok = false;
121	  if (current) ok = timingSafeEqual(provided, current) || ok;
122	  if (previous) ok = timingSafeEqual(provided, previous) || ok;
123	  return ok;
124	}
125	
126	function validResource(value: unknown): value is ApifyResource {
127	  if (!value || typeof value !== "object") return false;
128	  const r = value as Record<string, unknown>;
129	  return (
130	    isNonEmptyString(r.id) &&
131	    isNonEmptyString(r.defaultDatasetId) &&
132	    isNonEmptyString(r.status) &&
133	    isNonEmptyString(r.actId)
134	  );
135	}
136	
137	function meanPlayCount(items: TikTokItem[]): number | null {
138	  const slice = items.slice(0, 10);
139	  const views: number[] = [];
140	  for (const it of slice) {
141	    if (typeof it?.playCount === "number" && Number.isFinite(it.playCount)) {
142	      views.push(it.playCount);
143	    }
144	  }
145	  if (views.length === 0) return null;
146	  const sum = views.reduce((acc, n) => acc + n, 0);
147	  return Math.round(sum / views.length);
148	}
149	
150	async function fetchDatasetItems(
151	  datasetId: string,
152	  apifyKey: string,
153	): Promise<unknown[]> {
154	  const url = new URL(`${APIFY_API_BASE}/datasets/${datasetId}/items`);
155	  url.searchParams.set("token", apifyKey);
156	  url.searchParams.set("clean", "1");
157	  const res = await fetch(url.toString(), { method: "GET" });
158	  if (!res.ok) {
159	    // Don't include res body — Apify can echo the token-carrying URL inside
160	    // error payloads, and this lands in edge-function logs.
161	    throw new Error(
162	      `Apify dataset '${datasetId}' fetch failed: ${res.status} ${res.statusText}`,
163	    );
164	  }
165	  const items = await res.json();
166	  if (!Array.isArray(items)) {
167	    throw new Error(`Apify dataset '${datasetId}' returned non-array payload`);
168	  }
169	  return items;
170	}
171	
172	Deno.serve(async (req) => {
173	  if (req.method === "OPTIONS") {
174	    return new Response(null, { status: 204, headers: corsHeaders });
175	  }
176	  if (req.method !== "POST") {
177	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
178	  }
179	
180	  if (!verifyWebhookSecret(req)) {
181	    return jsonResponse(401, { error: "UNAUTHORIZED" });
182	  }
183	
184	  let body: WebhookBody;
185	  try {
186	    body = await req.json();
187	  } catch {
188	    return jsonResponse(400, { error: "INVALID_JSON" });
189	  }
190	
191	  if (
192	    !isNonEmptyString(body.eventType) ||
193	    !TERMINAL_EVENT_TYPES.has(body.eventType) ||
194	    !validResource(body.resource) ||
195	    !isNonEmptyString(body.social_link_id) ||
196	    !isNonEmptyString(body.scrape_mode) ||
197	    !isNonEmptyString(body.run_id)
198	  ) {
199	    return jsonResponse(400, { error: "INVALID_REQUEST" });
200	  }
201	
202	  const scrapeMode = body.scrape_mode as ScrapeMode;
203	  if (scrapeMode !== "tiktok_profile") {
204	    // ig_details / ig_posts are wired in US-017; return 200 so Apify does not
205	    // retry. The social_link_id is intentionally not logged here — the row
206	    // will still be stuck 'refreshing' until the fail-stuck-refreshing cron
207	    // janitor (docs/tech-architecture.md §15) flips it to 'failed'.
208	    return jsonResponse(200, { ok: true, skipped: "unsupported_scrape_mode" });
209	  }
210	
211	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
212	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
213	  if (!supabaseUrl || !serviceRoleKey) {
214	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
215	  }
216	
217	  const resource = body.resource as ApifyResource;
218	  const runId = body.run_id;
219	  const socialLinkId = body.social_link_id;
220	  const fetchedAt = isNonEmptyString(body.apify_finished_at)
221	    ? body.apify_finished_at
222	    : new Date().toISOString();
223	
224	  let nextStatus: MetricStatus;
225	  let followerCount: number | null = null;
226	  let followingCount: number | null = null;
227	  let totalLikes: number | null = null;
228	  let videoCount: number | null = null;
229	  let avgViewsLast10: number | null = null;
230	  let isVerified: boolean | null = null;
231	  let rawPayload: unknown = null;
232	  let errorMessage: string | null = null;
233	
234	  if (body.eventType === SUCCEEDED_EVENT) {
235	    const apifyKey = Deno.env.get("APIFY_KEY");
236	    if (!apifyKey) {
237	      return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
238	    }
239	    let items: unknown[];
240	    try {
241	      items = await fetchDatasetItems(resource.defaultDatasetId, apifyKey);
242	    } catch (err) {
243	      console.error("apify dataset fetch failed", {
244	        run_id: runId,
245	        dataset_id: resource.defaultDatasetId,
246	        error: err instanceof Error ? err.message : String(err),
247	      });
248	      return jsonResponse(500, { error: "APIFY_FETCH_ERROR" });
249	    }
250	    rawPayload = items;
251	    const tiktokItems = items as TikTokItem[];
252	    const first = tiktokItems[0];
253	    const authorMeta = first?.authorMeta;
254	    if (authorMeta) {
255	      followerCount = typeof authorMeta.fans === "number" ? authorMeta.fans : null;
256	      followingCount = typeof authorMeta.following === "number"
257	        ? authorMeta.following
258	        : null;
259	      totalLikes = typeof authorMeta.heart === "number" ? authorMeta.heart : null;
260	      videoCount = typeof authorMeta.video === "number" ? authorMeta.video : null;
261	      isVerified = typeof authorMeta.verified === "boolean"
262	        ? authorMeta.verified
263	        : null;
264	    }
265	    avgViewsLast10 = meanPlayCount(tiktokItems);
266	    nextStatus = "fresh";
267	  } else {
268	    nextStatus = "failed";
269	    errorMessage = `apify_${body.eventType.toLowerCase().replace(/\./g, "_")}`;
270	    rawPayload = { resource, eventType: body.eventType };
271	  }
272	
273	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
274	    auth: { persistSession: false, autoRefreshToken: false },
275	  });
276	
277	  const { data, error } = await supabase.rpc(
278	    "apify_webhook_persist_tiktok_profile",
279	    {
280	      p_run_id: runId,
281	      p_social_link_id: socialLinkId,
282	      p_status: nextStatus,
283	      p_fetched_at: fetchedAt,
284	      p_follower_count: followerCount,
285	      p_following_count: followingCount,
286	      p_total_likes: totalLikes,
287	      p_video_count: videoCount,
288	      p_avg_views_last_10: avgViewsLast10,
289	      p_is_verified: isVerified,
290	      p_raw_payload: rawPayload as never,
291	      p_error_message: errorMessage,
292	    },
293	  );
294	
295	  if (error) {
296	    console.error("apify_webhook_persist_tiktok_profile rpc error", {
297	      run_id: runId,
298	      code: error.code,
299	      message: error.message,
300	    });
301	    return jsonResponse(500, { error: "DB_ERROR" });
302	  }
303	
304	  const result = data as {
305	    inserted?: boolean;
306	    duplicate?: boolean;
307	    snapshot_id?: string;
308	  } | null;
309	
310	  return jsonResponse(200, {
311	    ok: true,
312	    inserted: result?.inserted === true,
313	    duplicate: result?.duplicate === true,
314	  });
315	});
