1	// Smoke test for the deployed apify-webhook edge function (US-016).
2	//
3	// Usage: bun run scripts/test/apify-webhook.ts
4	// Requires SUPABASE_URL, SUPABASE_ANON_KEY, APIFY_WEBHOOK_SECRET in .env.
5	//
6	// Covers the paths that don't need a live Apify run — the SUCCEEDED branch
7	// (which pulls a real dataset) is exercised end-to-end in the iteration's
8	// MCP verification, not here.
9	//
10	// Asserts:
11	//   1. Missing X-Apify-Webhook-Secret → 401 UNAUTHORIZED
12	//   2. Wrong secret → 401 UNAUTHORIZED (constant-time reject)
13	//   3. Malformed JSON body with valid secret → 400 INVALID_JSON
14	//   4. Missing required fields → 400 INVALID_REQUEST
15	//   5. scrape_mode='ig_details' → 200 { skipped:'unsupported_scrape_mode' }
16	//   6. tiktok_profile + ACTOR.RUN.FAILED → 200 { inserted:true, duplicate:false }
17	//   7. Replay same run_id → 200 { inserted:false, duplicate:true }
18	
19	const supabaseUrl = process.env.SUPABASE_URL;
20	const anonKey = process.env.SUPABASE_ANON_KEY;
21	const webhookSecret = process.env.APIFY_WEBHOOK_SECRET;
22	if (!supabaseUrl || !anonKey || !webhookSecret) {
23	  console.error(
24	    "SUPABASE_URL, SUPABASE_ANON_KEY, and APIFY_WEBHOOK_SECRET are required in .env",
25	  );
26	  process.exit(1);
27	}
28	
29	const endpoint = `${supabaseUrl}/functions/v1/apify-webhook`;
30	// anon key is required by the Supabase gateway even for verify_jwt=false
31	// functions; the edge function itself validates X-Apify-Webhook-Secret.
32	const gatewayHeaders = {
33	  Authorization: `Bearer ${anonKey}`,
34	  apikey: anonKey,
35	};
36	
37	const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";
38	const unique = Date.now();
39	
40	function basePayload(overrides: Record<string, unknown> = {}) {
41	  const runId = `us016_test_${unique}_${Math.random().toString(36).slice(2, 10)}`;
42	  return {
43	    eventType: "ACTOR.RUN.FAILED",
44	    resource: {
45	      id: runId,
46	      defaultDatasetId: `dataset_${runId}`,
47	      status: "FAILED",
48	      actId: "clockworks~tiktok-scraper",
49	    },
50	    social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID,
51	    scrape_mode: "tiktok_profile",
52	    run_id: runId,
53	    apify_finished_at: new Date().toISOString(),
54	    ...overrides,
55	  };
56	}
57	
58	async function postRaw(
59	  body: string | object,
60	  extraHeaders: Record<string, string> = {},
61	) {
62	  const res = await fetch(endpoint, {
63	    method: "POST",
64	    headers: {
65	      "Content-Type": "application/json",
66	      ...gatewayHeaders,
67	      ...extraHeaders,
68	    },
69	    body: typeof body === "string" ? body : JSON.stringify(body),
70	  });
71	  const data = await res.json().catch(() => null);
72	  return { status: res.status, data };
73	}
74	
75	function expect(label: string, cond: boolean, ctx: unknown) {
76	  if (!cond) {
77	    console.error(`FAIL ${label}:`, ctx);
78	    process.exit(1);
79	  }
80	  console.log(`ok — ${label}`);
81	}
82	
83	// 1. Missing secret header
84	{
85	  const r = await postRaw(basePayload());
86	  expect(
87	    "missing secret → 401 UNAUTHORIZED",
88	    r.status === 401 && r.data?.error === "UNAUTHORIZED",
89	    r,
90	  );
91	}
92	
93	// 2. Wrong secret header
94	{
95	  const r = await postRaw(basePayload(), {
96	    "X-Apify-Webhook-Secret": "definitely-not-the-real-secret",
97	  });
98	  expect(
99	    "wrong secret → 401 UNAUTHORIZED",
100	    r.status === 401 && r.data?.error === "UNAUTHORIZED",
101	    r,
102	  );
103	}
104	
105	// 3. Malformed JSON (valid secret)
106	{
107	  const r = await postRaw("{not json", {
108	    "X-Apify-Webhook-Secret": webhookSecret,
109	  });
110	  expect(
111	    "malformed json → 400 INVALID_JSON",
112	    r.status === 400 && r.data?.error === "INVALID_JSON",
113	    r,
114	  );
115	}
116	
117	// 4. Missing required fields
118	{
119	  const r = await postRaw(
120	    { eventType: "ACTOR.RUN.SUCCEEDED" },
121	    { "X-Apify-Webhook-Secret": webhookSecret },
122	  );
123	  expect(
124	    "missing fields → 400 INVALID_REQUEST",
125	    r.status === 400 && r.data?.error === "INVALID_REQUEST",
126	    r,
127	  );
128	}
129	
130	// 5. ig_details scrape_mode → unsupported_scrape_mode
131	{
132	  const r = await postRaw(
133	    basePayload({ scrape_mode: "ig_details" }),
134	    { "X-Apify-Webhook-Secret": webhookSecret },
135	  );
136	  expect(
137	    "ig_details → 200 skipped",
138	    r.status === 200 && r.data?.skipped === "unsupported_scrape_mode",
139	    r,
140	  );
141	}
142	
143	// 6. tiktok_profile + FAILED event → inserts failed snapshot
144	const failedRunBody = basePayload();
145	{
146	  const r = await postRaw(failedRunBody, {
147	    "X-Apify-Webhook-Secret": webhookSecret,
148	  });
149	  expect(
150	    "tiktok_profile FAILED → 200 inserted",
151	    r.status === 200 && r.data?.inserted === true && r.data?.duplicate === false,
152	    r,
153	  );
154	}
155	
156	// 7. Same run_id replay → idempotent duplicate
157	{
158	  const r = await postRaw(failedRunBody, {
159	    "X-Apify-Webhook-Secret": webhookSecret,
160	  });
161	  expect(
162	    "replay same run_id → 200 duplicate",
163	    r.status === 200 && r.data?.inserted === false && r.data?.duplicate === true,
164	    r,
165	  );
166	}
167	
168	console.log("all apify-webhook smoke tests passed");
