1	// Live end-to-end for the apify-webhook SUCCEEDED branch (US-016).
2	//
3	// Usage: bun run scripts/test/apify-webhook-live.ts
4	// Requires APIFY_KEY, APIFY_WEBHOOK_SECRET, SUPABASE_URL, SUPABASE_ANON_KEY.
5	//
6	// Hits a real Apify actor (spends a few cents) and therefore is not part of
7	// the default smoke suite. This script only drives the *request side*:
8	//   1. Kick a real Apify tiktok_profile run (sync wait ≤ 90s)
9	//   2. POST a synthetic webhook carrying the real run_id + defaultDatasetId
10	//   3. Assert the webhook returned 200 inserted:true duplicate:false
11	//
12	// The DB-side assertions (metric_snapshots row written, creator_profiles
13	// denorm trigger fired) are done separately via Supabase MCP execute_sql
14	// after this script completes — see progress.txt entry for US-016.
15	
16	const {
17	  APIFY_KEY,
18	  APIFY_WEBHOOK_SECRET,
19	  SUPABASE_URL,
20	  SUPABASE_ANON_KEY,
21	} = process.env;
22	
23	if (!APIFY_KEY || !APIFY_WEBHOOK_SECRET || !SUPABASE_URL || !SUPABASE_ANON_KEY) {
24	  console.error(
25	    "APIFY_KEY, APIFY_WEBHOOK_SECRET, SUPABASE_URL, SUPABASE_ANON_KEY required in .env",
26	  );
27	  process.exit(1);
28	}
29	
30	const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";
31	const TIKTOK_HANDLE = "tiktok"; // cheap + stable public account
32	const endpoint = `${SUPABASE_URL}/functions/v1/apify-webhook`;
33	
34	console.log(`kicking Apify tiktok_profile for @${TIKTOK_HANDLE}...`);
35	const runUrl = new URL(
36	  "https://api.apify.com/v2/acts/clockworks~tiktok-scraper/runs",
37	);
38	runUrl.searchParams.set("token", APIFY_KEY);
39	runUrl.searchParams.set("waitForFinish", "90");
40	
41	const runRes = await fetch(runUrl.toString(), {
42	  method: "POST",
43	  headers: { "content-type": "application/json" },
44	  body: JSON.stringify({
45	    profiles: [TIKTOK_HANDLE],
46	    resultsPerPage: 10,
47	    profileScrapeSections: ["videos"],
48	    profileSorting: "latest",
49	    excludePinnedPosts: true,
50	    shouldDownloadVideos: false,
51	    shouldDownloadCovers: false,
52	  }),
53	});
54	if (!runRes.ok) {
55	  console.error(`apify start failed: ${runRes.status} ${runRes.statusText}`);
56	  process.exit(1);
57	}
58	const runJson = (await runRes.json()) as {
59	  data?: { id?: string; defaultDatasetId?: string; status?: string };
60	};
61	const runData = runJson.data;
62	if (
63	  !runData?.id ||
64	  !runData.defaultDatasetId ||
65	  runData.status !== "SUCCEEDED"
66	) {
67	  console.error("apify run did not succeed:", runData);
68	  process.exit(1);
69	}
70	console.log(
71	  `apify run ${runData.id} ${runData.status}, dataset ${runData.defaultDatasetId}`,
72	);
73	
74	const webhookRes = await fetch(endpoint, {
75	  method: "POST",
76	  headers: {
77	    "Content-Type": "application/json",
78	    Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
79	    apikey: SUPABASE_ANON_KEY,
80	    "X-Apify-Webhook-Secret": APIFY_WEBHOOK_SECRET,
81	  },
82	  body: JSON.stringify({
83	    eventType: "ACTOR.RUN.SUCCEEDED",
84	    resource: {
85	      id: runData.id,
86	      defaultDatasetId: runData.defaultDatasetId,
87	      status: "SUCCEEDED",
88	      actId: "clockworks~tiktok-scraper",
89	    },
90	    social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID,
91	    scrape_mode: "tiktok_profile",
92	    run_id: runData.id,
93	    apify_finished_at: new Date().toISOString(),
94	  }),
95	});
96	const webhookBody = await webhookRes.json();
97	console.log("webhook response:", webhookRes.status, webhookBody);
98	if (
99	  webhookRes.status !== 200 ||
100	  webhookBody.inserted !== true ||
